  `note` varchar(500) DEFAULT NULL,
  `design_id` int DEFAULT NULL,
  `size_id` varchar(50) DEFAULT NULL,
  `color_id` int DEFAULT NULL,
  `fabric_id` int DEFAULT NULL,
  `cat_id` int DEFAULT NULL,
  `unit_id` int DEFAULT NULL,
  `con_ratio` float DEFAULT '0',
  `pur_rate` double DEFAULT '0',
  `rd_amt` float DEFAULT NULL,
  `dis_per` float DEFAULT NULL,
  `sp_dis_per` float DEFAULT NULL,
  `gst_per` float DEFAULT NULL,
  `gst_amt` float NOT NULL DEFAULT '0',
  `is_faction` int DEFAULT '0',
  `mrp_rate` double DEFAULT '0',
  `sale_rate` double DEFAULT '0',
  `online_rate` double DEFAULT '0',
  `markupamt` double NOT NULL DEFAULT '0',
  `entry_meter` float DEFAULT '0',
  `entry_qty` float DEFAULT '0',
  `entry_return_meter` float DEFAULT '0',
  `entry_return_qty` float DEFAULT '0',
  `issue_meter` float DEFAULT '0',
  `issue_qty` float DEFAULT '0',
  `issue_return_meter` float DEFAULT '0',
  `issue_return_qty` float DEFAULT '0',
  `stock_transfer` float DEFAULT '0',
  `stock_return` float DEFAULT '0',
  `mate_issued` float DEFAULT '0',
  `issued_recived` float DEFAULT '0',
  `value_addition` float DEFAULT '0',
  `cur_meter` float DEFAULT '0',
  `cur_qty` float DEFAULT '0',
  `additon_image` varchar(200) DEFAULT NULL,
  `status` enum('1','0') NOT NULL DEFAULT '1',
  `item_remarks` text,
  `indate` date NOT NULL,
  `insert_date` varchar(40) DEFAULT NULL,
