DROP TABLE IF EXISTS `ba2_purchase_master`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ba2_purchase_master` (
  `id` int NOT NULL AUTO_INCREMENT,
  `comid` int DEFAULT NULL,
  `warehouse_id` int NOT NULL DEFAULT '1',
  `incno` int NOT NULL,
  `groc_entry` int DEFAULT '0',
  `orderid` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invoiceid` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `inv_type` int DEFAULT '0',
  `pur_type` int NOT NULL DEFAULT '1',
  `grntype` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `grndate` date DEFAULT NULL,
  `party_id` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invno` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `invdate` date DEFAULT NULL,
  `lrno` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `lrdate` date DEFAULT NULL,
  `transporter_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mode_transport` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tot_qty` float DEFAULT NULL,
  `tot_amt` float DEFAULT NULL,
  `pack_charge` float DEFAULT '0',
  `disper` float DEFAULT NULL,
  `disamt` float DEFAULT NULL,
  `tax_amount` float DEFAULT '0',
  `other_charge` float DEFAULT '0',
  `lessper` float DEFAULT NULL,
  `lessamt` float DEFAULT NULL,
  `freight` float DEFAULT NULL,
  `round_off` float DEFAULT NULL,
  `taxvalue` float DEFAULT NULL,
  `gst_per` float DEFAULT NULL,
  `gst_amt` float DEFAULT NULL,
  `grand_tot` float DEFAULT NULL,
  `payment_amt` float DEFAULT '0',
  `payment_billno` int DEFAULT NULL,
  `bankdt` int DEFAULT NULL,
  `desc_text` text COLLATE utf8mb4_unicode_ci,
  `roundof_type` int DEFAULT '1',
  `jsan_data` text COLLATE utf8mb4_unicode_ci,
  `excel_file_name` varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pdf_file` varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `entry_date` date DEFAULT NULL,
  `status` enum('1','0') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '1',
  `insert_date` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `insert_user` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `update_date` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `update_user` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `entydatetime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`incno`),
  KEY `id` (`id`,`incno`,`orderid`,`invoiceid`,`inv_type`,`party_id`,`invno`,`transporter_id`)
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
