/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ba3_purchase_details` (
  `id` int NOT NULL AUTO_INCREMENT,
  `comid` int DEFAULT NULL,
  `incno` int DEFAULT NULL,
  `invtype` int DEFAULT NULL,
  `purtype` int NOT NULL DEFAULT '1',
  `itemid` int DEFAULT NULL,
  `batchno` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mfgdate` date DEFAULT NULL,
  `expirydate` date DEFAULT NULL,
  `serialimeino` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `warrantyperiod` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `modelno` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `powervoltage` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hsncode` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `brand_id` int DEFAULT NULL,
  `edition` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `design_id` int DEFAULT NULL,
  `barcode` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `size` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `color_id` int DEFAULT NULL,
  `fabric_id` int DEFAULT NULL,
  `category_id` int DEFAULT NULL,
  `unit_id` int DEFAULT NULL,
  `meter` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `qty` float DEFAULT NULL,
  `free_qty` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rate` double DEFAULT NULL,
  `rd_amt` float DEFAULT NULL,
  `disc_per` float DEFAULT NULL,
  `disc_amt` float DEFAULT '0',
  `sp_dis` float DEFAULT NULL,
  `pursinamt` float NOT NULL DEFAULT '0',
  `totalamt` float DEFAULT NULL,
  `gstper` float DEFAULT NULL,
  `gstamt` float NOT NULL DEFAULT '0',
  `purchase_amt` float DEFAULT '0',
  `with_faction` int DEFAULT '0',
  `mrp_price` double DEFAULT NULL,
  `sale_price` double DEFAULT NULL,
  `online_price` double DEFAULT NULL,
  `markupamt` double NOT NULL DEFAULT '0',
  `status` enum('1','0') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '1',
  `insert_date` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `insert_user` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `update_date` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `update_user` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `id` (`id`,`incno`,`invtype`,`itemid`,`brand_id`,`design_id`,`color_id`,`fabric_id`,`category_id`,`unit_id`)
) ENGINE=InnoDB AUTO_INCREMENT=745 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
